public class ETG_SellerBankAccountUpdation extends RunBase
{
    CustInvoiceJour         custInvoiceJour;
    CompanyBankAccountId    sellerBankAccount;
    DialogRunBase           dialog;
    DialogField             dlgSellerBankAccount;

    #define.CurrentVersion(1)
    #define.Version1(1)


}

Method.Source:
/// <summary>
/// Main method to run the process
/// </summary>
static void main(Args args)
{
    ETG_SellerBankAccountUpdation   sellerBankUpdation;
    FormRun                         formRun;
    FormDataSource                  formDataSource;
    CustInvoiceJour                 custInvoiceJourLoc;

    // verify the args
    if (!args)
    {
        throw error("Invalid arguments passed.");
    }

    // Get the form run instance
    formRun = args.caller() as FormRun;

    if (!formRun)
    {
        throw error("Form is not open.");
    }

    // Get the correct data source from the form
    formDataSource  =   formRun.dataSource(formDataSourceStr(CustInvoiceJournal, CustInvoiceJour));

    if (!formDataSource)
    {
        throw error("Data source not found.");
    }

    // Get the currently selected record
    custInvoiceJourLoc = formDataSource.cursor();

    if (!custInvoiceJourLoc || !custInvoiceJourLoc.RecId)
    {
        throw error("No record selected.");
    }

    // Initialize the dialog and pass the selected record
    sellerBankUpdation  =   new ETG_SellerBankAccountUpdation();

    sellerBankUpdation.parmCustInvoiceJour(custInvoiceJourLoc);

    if (sellerBankUpdation.prompt())
    {
        sellerBankUpdation.run();
        formDataSource.refresh();
        formDataSource.research();

    }
}

/// <summary>
/// Dialog for selecting a new Seller Bank Account
/// </summary>
public Object dialog()
{
    dialog = super();

    // Correct field type
    dlgSellerBankAccount = dialog.addField(extendedTypeStr(CompanyBankAccountId), 'Seller Bank Account');

    return dialog;
}

// <summary>
/// Runs after the dialog is opened
/// </summary>
public void dialogPostRun(DialogRunBase _dialog)
{
    super(_dialog);

    _dialog.formRun().controlMethodOverload(true);
    _dialog.formRun().controlMethodOverloadObject(this);
}

/// <summary>
/// Lookup method for Seller Bank Account
/// </summary>
private void SellerBankAccount_lookup()
{
    FormControl     formControl =   dlgSellerBankAccount.control();

    BankAccountTable::lookupBankAccount(formControl);
}

public CustInvoiceJour parmCustInvoiceJour(CustInvoiceJour _custInvoiceJour = custInvoiceJour)
{
    custInvoiceJour = _custInvoiceJour;

    return custInvoiceJour;
}

/// <summary>
/// Retrieves selected values from the dialog
/// </summary>
public boolean getFromDialog()
{
    sellerBankAccount   =   dlgSellerBankAccount.value();

    return true;
}

/// <summary>
/// Business logic to update the Seller Bank Account
/// </summary>
public void run()
{
    CustInvoiceJour custInvoiceJourSellerBank;

    // Select the correct record for update
    ttsbegin;

    select InvoiceId,ETG_SellerBankDetails from custInvoiceJourSellerBank
        where custInvoiceJourSellerBank.InvoiceId == this.custInvoiceJour.InvoiceId;

    custInvoiceJourSellerBank.reread();

    if (custInvoiceJourSellerBank.RecId)   // Ensure record exists
    {
        custInvoiceJourSellerBank.selectForUpdate(true);
        custInvoiceJourSellerBank.skipDatabaseLog(true);
        custInvoiceJourSellerBank.skipBusinessEvents(true);

        custInvoiceJourSellerBank.ETG_SellerBankDetails =   sellerBankAccount;

        custInvoiceJourSellerBank.doUpdate();  // Update properly

    }
    else
    {
        throw error("Customer invoice journal record not found or not selected.");
    }

    ttscommit;
}

/// <summary>
/// Pack method for serialization
/// </summary>
public container pack()
{
    return [#CurrentVersion, custInvoiceJour.RecId, sellerBankAccount];
}

/// <summary>
/// Unpack method for deserialization
/// </summary>
public boolean unpack(container packedClass)
{
    Version version = RunBase::getVersion(packedClass);

    switch (version)
    {
        case #CurrentVersion:

            [version, custInvoiceJour.RecId, sellerBankAccount] = packedClass;
            return true;

        default:
            return false;
    }
}
